// 1. Primitiv sabitlər
public class PrimitiveConstants {
  public static void main(String[] args) {
    final int MAX_USERS = 100; // Primitiv sabit
    final double PI = 3.14159;
    // MAX_USERS = 200; // Səhv: Sabit dəyişdirilə bilməz
    System.out.println("Max Users: " + MAX_USERS + ", PI: " + PI);
  }
}
// Çıxış: Max Users: 100, PI: 3.14159

// 2. Qeyri-primitiv sabitlər
public class NonPrimitiveConstants {
  public static void main(String[] args) {
    final String APP_NAME = "MyApp"; // String sabit
    // APP_NAME = "NewApp"; // Səhv: Sabit dəyişdirilə bilməz
    System.out.println("App Name: " + APP_NAME);
  }
}
// Çıxış: App Name: MyApp

// 3. Sinifdə sabitlər
public class Circle {
  final double PI = 3.14159; // Nümunə sabiti
  static final double DEFAULT_RADIUS = 1.0; // Statik sabit
  double radius;

  public Circle(double radius) {
    this.radius = radius;
  }

  public double getArea() {
    return PI * radius * radius;
  }

  public static void main(String[] args) {
    Circle circle = new Circle(DEFAULT_RADIUS);
    System.out.println("Area: " + circle.getArea());
  }
}
// Çıxış: Area: 3.14159

public class ScopeConstants {
  static final int GLOBAL_LIMIT = 1000; // Statik sabit
  final int INSTANCE_LIMIT = 500; // Nümunə sabiti

  public void checkLimit() {
    final int LOCAL_LIMIT = 50; // Lokal sabit
    System.out.println("Local: " + LOCAL_LIMIT + ", Instance: " + INSTANCE_LIMIT + ", Global: " + GLOBAL_LIMIT);
  }

  public static void main(String[] args) {
    ScopeConstants obj1 = new ScopeConstants();
    ScopeConstants obj2 = new ScopeConstants();
    obj1.checkLimit();
    obj2.checkLimit();
    System.out.println("Global Limit: " + GLOBAL_LIMIT);
  }
}
// Çıxış: Local: 50, Instance: 500, Global: 1000
// Local: 50, Instance: 500, Global: 1000
// Global Limit: 1000

public class Store {
  static final double TAX_RATE = 0.18; // Statik sabit
  final String STORE_NAME = "TechShop"; // Nümunə sabiti
  String productName;
  double price;

  public Store(String productName, double price) {
    this.productName = productName;
    this.price = price;
  }

  public double calculateTotalPrice() {
    return price + (price * TAX_RATE);
  }

  public String getInfo() {
    return "Store: " + STORE_NAME + ", Product: " + productName + ", Total Price: " + calculateTotalPrice();
  }

  public static void main(String[] args) {
    Store store = new Store("Laptop", 999.99);
    System.out.println(store.getInfo());
  }
}
// Çıxış: Store: TechShop, Product: Laptop, Total Price: 1179.98782

